import { MinusCircleOutlined, PlusCircleFilled } from '@ant-design/icons';
import React, { useState } from 'react';
import {  Card, Switch } from 'antd';
import { Button, Tooltip } from 'antd';


const CardItem: React.FC = () => {
  const [loading, setLoading] = useState<boolean>(true);
  const [Counter, setCounter] = useState<number>(1);

  const onChange = (checked: boolean) => {
    setLoading(!checked);
  };

  return (
    <>
      <Switch checked={!loading} onChange={onChange} />
      <Card style={{ width: 340, marginTop: 16 }} loading={loading}>
      <div className='Card_Counter'>

        <Tooltip title="Plus">
        <Button  shape="circle" icon={<PlusCircleFilled />} />
      </Tooltip>

      <Tooltip title="Minus">
        <Button  shape="circle" icon={<MinusCircleOutlined />} />
      </Tooltip>
      </div>
      </Card>

    </>
  );
};

export default CardItem;
